import React from 'react';
import './StreakBadge.css';

const getStreakTier = (count) => {
    if (count >= 100) return 'legendary';
    if (count >= 30) return 'inferno';
    if (count >= 14) return 'blazing';
    if (count >= 7) return 'burning';
    if (count >= 1) return 'ember';
    return null;
};

