105→const attachRepostSources = async (journals) => {
106→    const items = Array.isArray(journals) ? journals : [journals];
107→    const sourceIds = [...new Set(
108→        items
109→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
110→            .map(j => j.repost_source_journal_id)
111→    )];
112→
113→    if (sourceIds.length === 0) {
114→        items.forEach(j => { j.repost_source = null; });
115→        return journals;
116→    }
117→
118→    const { data: sources, error } = await supabase
119→        .from('journals')
120→        .select('id, title, content, post_type, canvas_doc, created_at, users(id, name, image_url, badge)')
121→        .in('id', sourceIds);
122→
123→    if (error) {
124→        console.error('supabase error fetching repost sources:', error.message);
125→        items.forEach(j => { j.repost_source = null; });
126→        return journals;
127→    }
128→
129→    const sourceMap = new Map(sources.map(s => [s.id, s]));
130→    items.forEach(j => {
131→        j.repost_source = j.repost_source_journal_id
132→            ? (sourceMap.get(j.repost_source_journal_id) || null)
133→            : null;
134→    });
135→
136→    return journals;
137→};
